   135→app.get('/api/admin/metrics', requireAdmin, async (req, res) => {
   136→  try {
   137→    const { getAllMetrics } = require('./lib/metrics-collector');
   138→    const metrics = await getAllMetrics();
   139→    res.json(metrics);
   140→  } catch (err) {
   141→    res.status(500).json({ error: 'Failed to get metrics', message: err.message });
   142→  }
   143→});
   144→
   145→// Activity Feed — protected by admin auth
   146→app.get('/api/admin/activity', requireAdmin, async (req, res) => {
   147→  try {
   148→    const { queryEvents, getRecentEvents } = require('./lib/activity-logger');
   149→    const { category, event_type, user_id, search, start_date, end_date, limit, offset, realtime } = req.query;
   150→
   151→    // Real-time mode: return from in-memory buffer (fast, no DB)
   152→    if (realtime === 'true') {
   153→      const events = getRecentEvents({ category, eventType: event_type, limit: parseInt(limit, 10) || 50 });
   154→      return res.json({ events, total: events.length, source: 'memory' });
   155→    }
   156→
   157→    // Historical mode: query from database
   158→    const result = await queryEvents({
   159→      category,
   160→      eventType: event_type,
   161→      userId: user_id ? parseInt(user_id, 10) : undefined,
   162→      search,
   163→      startDate: start_date,
   164→      endDate: end_date,
   165→      limit: parseInt(limit, 10) || 50,
   166→      offset: parseInt(offset, 10) || 0,
   167→    });
   168→
   169→    res.json({ ...result, source: 'database' });
   170→  } catch (err) {
   171→    res.status(500).json({ error: 'Failed to get activity log', message: err.message });
   172→  }
   173→});
   174→
   175→// OpenAI Token Budget — protected by admin auth
   176→app.get('/api/admin/token-usage', requireAdmin, (req, res) => {
   177→  try {
   178→    const tokenBudget = require('./lib/token-budget');
   179→    res.json(tokenBudget.getStatus());
   180→  } catch (err) {
   181→    res.status(500).json({ error: 'Failed to get token usage', message: err.message });
   182→  }
   183→});
   184→
   185→// AI Provider Health — protected by admin auth
   186→app.get('/api/ai-health', requireAdmin, (req, res) => {
   187→  try {
   188→    const { aiProvider } = require('./lib/polsia-ai');
   189→    res.json(aiProvider.getHealth());
   190→  } catch (err) {
   191→    res.status(500).json({ error: 'Failed to get AI health status', message: err.message });
   192→  }
   193→});
   194→
   195→// Reset AI provider circuit breakers — protected by admin auth
   196→app.post('/api/ai-health/reset', requireAdmin, (req, res) => {
   197→  try {
   198→    const { aiProvider } = require('./lib/polsia-ai');
   199→    aiProvider.resetCircuitBreakers();
   200→    res.json({ success: true, message: 'All circuit breakers reset', health: aiProvider.getHealth() });
   201→  } catch (err) {
   202→    res.status(500).json({ error: 'Failed to reset circuit breakers', message: err.message });
   203→  }
   204→});
   205→
   206→// POST /api/ai-health/verify — run real API calls to verify ALL providers across ALL modalities
   207→app.post('/api/ai-health/verify', requireAdmin, async (req, res) => {
   208→  try {
   209→    const { aiProvider } = require('./lib/polsia-ai');
   210→    const result = await aiProvider.verifyModels();
   211→    res.json(result);
   212→  } catch (err) {
   213→    res.status(500).json({ error: 'Model verification failed', message: err.message });
   214→  }
   215→});
   216→
   217→// GET /api/ai-health/verify-status — get last verification results + auto-verify status
   218→app.get('/api/ai-health/verify-status', requireAdmin, (req, res) => {
   219→  try {
   220→    const { aiProvider } = require('./lib/polsia-ai');
   221→    const last = aiProvider.getLastVerification();
   222→    if (!last) {
   223→      return res.json({ verified: false, message: 'No verification run yet. Click "Verify Now" to run.' });
   224→    }
   225→    // Calculate age in minutes
   226→    const ageMs = Date.now() - new Date(last.timestamp).getTime();
   227→    const ageMinutes = Math.round(ageMs / 60000);
   228→    res.json({
   229→      verified: true,
   230→      ageMinutes,
   231→      stale: ageMinutes > 35, // auto-verify runs every 30min, flag if >35min
   232→      ...last,
   233→    });
   234→  } catch (err) {
   235→    res.status(500).json({ error: 'Failed to get verify status', message: err.message });
   236→  }
   237→});
   238→
   239→// ─── Auto-verify cron: run full verification every 30 minutes ─────────────
   240→// Minimal token cost (~3 tokens per model, ~60 tokens total per cycle)
   241→(function startAutoVerify() {
   242→  const AUTO_VERIFY_INTERVAL = 30 * 60 * 1000; // 30 minutes
   243→  // Run first verification 30s after startup (let all providers initialize)
   244→  setTimeout(async () => {
   245→    try {
   246→      const { aiProvider } = require('./lib/polsia-ai');
   247→      console.log('[auto-verify] Running initial verification...');
   248→      await aiProvider.verifyModels();
   249→      console.log('[auto-verify] Initial verification complete');
   250→    } catch (err) {
   251→      console.error('[auto-verify] Initial verification failed:', err.message);
   252→    }
   253→  }, 30000);
   254→
   255→  // Then every 30 minutes
   256→  setInterval(async () => {
   257→    try {
   258→      const { aiProvider } = require('./lib/polsia-ai');
   259→      console.log('[auto-verify] Running scheduled verification...');
   260→      await aiProvider.verifyModels();
   261→      console.log('[auto-verify] Scheduled verification complete');
   262→    } catch (err) {
   263→      console.error('[auto-verify] Scheduled verification failed:', err.message);
   264→    }
   265→  }, AUTO_VERIFY_INTERVAL);
   266→})();
   267→
   268→// ─── AI Health Monitoring Endpoints ──────────────────────────────────────────
   269→// Comprehensive AI call logs, model metrics, budget predictions, prompt management
   270→
   271→// GET /api/ai-health/usage — usage summary with model + module breakdown
   272→app.get('/api/ai-health/usage', requireAdmin, (req, res) => {
   273→  try {
   274→    const aiCallLogger = require('./lib/ai-call-logger');
   275→    const tokenBudgetSvc = require('./lib/token-budget');
   276→    res.json({
   277→      summary: aiCallLogger.getUsageSummary(),
   278→      models: aiCallLogger.getModelMetrics(),
   279→      modules: aiCallLogger.getModuleBreakdown(),
   280→      hourly: aiCallLogger.getHourlyUsage(),
   281→      budget: tokenBudgetSvc.getStatus(),
   282→    });
   283→  } catch (err) {
   284→    res.status(500).json({ error: 'Failed to get usage', message: err.message });
   285→  }
   286→});
   287→
   288→// GET /api/ai-health/budget — budget status + predictions
   289→app.get('/api/ai-health/budget', requireAdmin, (req, res) => {
   290→  try {
   291→    const aiCallLogger = require('./lib/ai-call-logger');
   292→    const tokenBudgetSvc = require('./lib/token-budget');
   293→    const status = tokenBudgetSvc.getStatus();
   294→    res.json({
   295→      ...status,
   296→      prediction: aiCallLogger.getBudgetPrediction(status),
   297→      moduleBreakdown: aiCallLogger.getModuleBreakdown(),
   298→      throttleStatus: Object.entries(aiCallLogger.MODULE_PRIORITY).map(([mod, priority]) => ({
   299→        module: mod,
   300→        priority,
   301→        throttled: aiCallLogger.shouldThrottle(mod, status),
   302→      })),
   303→    });
   304→  } catch (err) {
   305→    res.status(500).json({ error: 'Failed to get budget', message: err.message });
   306→  }
   307→});
   308→
   309→// GET /api/ai-health/logs — searchable call logs
   310→app.get('/api/ai-health/logs', requireAdmin, async (req, res) => {
   311→  try {
   312→    const aiCallLogger = require('./lib/ai-call-logger');
   313→    const { module, modality, provider, success, start_date, end_date, limit, offset, realtime } = req.query;
   314→
   315→    if (realtime === 'true') {
   316→      const calls = aiCallLogger.getRecentCalls({
   317→        module, modality, provider,
   318→        success: success !== undefined ? success === 'true' : undefined,
   319→        limit: parseInt(limit, 10) || 50,
   320→      });
   321→      return res.json({ logs: calls, total: calls.length, source: 'memory' });
   322→    }
   323→
   324→    const result = await aiCallLogger.queryCallLogs({
   325→      module, modality, provider,
   326→      success: success !== undefined ? success === 'true' : undefined,
   327→      startDate: start_date,
   328→      endDate: end_date,
   329→      limit: parseInt(limit, 10) || 50,
   330→      offset: parseInt(offset, 10) || 0,
   331→    });
   332→    res.json({ ...result, source: 'database' });
   333→  } catch (err) {
   334→    res.status(500).json({ error: 'Failed to get logs', message: err.message });
   335→  }
   336→});
   337→
   338→// GET /api/ai-health/daily-breakdown — per-module daily token breakdown from DB
   339→app.get('/api/ai-health/daily-breakdown', requireAdmin, async (req, res) => {
   340→  try {
   341→    const pool = require('./lib/db');
   342→    const date = req.query.date || new Date().toISOString().substring(0, 10);
   343→    const result = await pool.query(
   344→      `SELECT module,
   345→              COUNT(*) as call_count,
   346→              COALESCE(SUM(total_tokens), 0) as total_tokens,
   347→              COALESCE(SUM(cost_estimate), 0) as total_cost,
   348→              COUNT(*) FILTER (WHERE success = false) as failures
   349→       FROM ai_call_log
   350→       WHERE created_at >= $1::date AND created_at < ($1::date + interval '1 day')
   351→       GROUP BY module
   352→       ORDER BY total_tokens DESC`,
   353→      [date]
   354→    );
   355→
   356→    // Calculate totals for percentage
   357→    const totalTokens = result.rows.reduce((s, r) => s + parseInt(r.total_tokens), 0);
   358→    const dailyBudget = 100000; // 100K daily budget
   359→
   360→    const breakdown = result.rows.map(r => ({
   361→      module: r.module,
   362→      call_count: parseInt(r.call_count),
   363→      total_tokens: parseInt(r.total_tokens),
   364→      total_cost: Math.round(parseFloat(r.total_cost) * 10000) / 10000,
   365→      failures: parseInt(r.failures),
   366→      pct_of_daily: totalTokens > 0 ? Math.round((parseInt(r.total_tokens) / totalTokens) * 1000) / 10 : 0,
   367→      pct_of_budget: Math.round((parseInt(r.total_tokens) / dailyBudget) * 1000) / 10,
   368→    }));
   369→
   370→    res.json({
   371→      date,
   372→      total_tokens: totalTokens,
   373→      total_calls: result.rows.reduce((s, r) => s + parseInt(r.call_count), 0),
   374→      daily_budget: dailyBudget,
   375→      budget_used_pct: Math.round((totalTokens / dailyBudget) * 1000) / 10,
   376→      modules: breakdown,
   377→    });
   378→  } catch (err) {
   379→    // Fallback to in-memory if DB table doesn't exist yet
   380→    if (err.message.includes('does not exist')) {
   381→      const aiCallLogger = require('./lib/ai-call-logger');
   382→      const modules = aiCallLogger.getModuleBreakdown();
   383→      const totalTokens = Object.values(modules).reduce((s, m) => s + m.totalTokens, 0);
   384→      res.json({
   385→        date: new Date().toISOString().substring(0, 10),
   386→        total_tokens: totalTokens,
   387→        total_calls: Object.values(modules).reduce((s, m) => s + m.calls, 0),
   388→        daily_budget: 100000,
   389→        budget_used_pct: Math.round((totalTokens / 100000) * 1000) / 10,
   390→        modules: Object.entries(modules).map(([mod, m]) => ({
   391→          module: mod,
   392→          call_count: m.calls,
   393→          total_tokens: m.totalTokens,
   394→          total_cost: m.cost,
   395→          failures: m.failures,
   396→          pct_of_daily: totalTokens > 0 ? Math.round((m.totalTokens / totalTokens) * 1000) / 10 : 0,
   397→          pct_of_budget: Math.round((m.totalTokens / 100000) * 1000) / 10,
   398→        })),
   399→      });
   400→    } else {
   401→      res.status(500).json({ error: 'Failed to get daily breakdown', message: err.message });
   402→    }
   403→  }
   404→});
   405→
   406→// GET /api/ai-health/models — per-model performance metrics
   407→app.get('/api/ai-health/models', requireAdmin, (req, res) => {
   408→  try {
   409→    const aiCallLogger = require('./lib/ai-call-logger');
   410→    res.json(aiCallLogger.getModelMetrics());
   411→  } catch (err) {
   412→    res.status(500).json({ error: 'Failed to get model metrics', message: err.message });
   413→  }
   414→});
   415→
   416→// GET /api/ai-health/failover-stats — failover analytics
   417→app.get('/api/ai-health/failover-stats', requireAdmin, (req, res) => {
   418→  try {
   419→    const aiCallLogger = require('./lib/ai-call-logger');
   420→    res.json(aiCallLogger.getFailoverStats());
   421→  } catch (err) {
   422→    res.status(500).json({ error: 'Failed to get failover stats', message: err.message });
   423→  }
   424→});
   425→
   426→// GET /api/ai-health/predictions — budget predictions + throttle status
   427→app.get('/api/ai-health/predictions', requireAdmin, (req, res) => {
   428→  try {
   429→    const aiCallLogger = require('./lib/ai-call-logger');
   430→    const tokenBudgetSvc = require('./lib/token-budget');
   431→    const status = tokenBudgetSvc.getStatus();
   432→    res.json({
   433→      prediction: aiCallLogger.getBudgetPrediction(status),
   434→      hourlyUsage: aiCallLogger.getHourlyUsage(),
   435→      throttleStatus: Object.entries(aiCallLogger.MODULE_PRIORITY).map(([mod, priority]) => ({
   436→        module: mod,
   437→        priority,
   438→        throttled: aiCallLogger.shouldThrottle(mod, status),
   439→      })),
   440→    });
   441→  } catch (err) {
   442→    res.status(500).json({ error: 'Failed to get predictions', message: err.message });
   443→  }
   444→});
   445→
   446→// ─── Prompt Management (Pezzo-style) ────────────────────────────────────────
   447→
   448→// GET /api/ai-health/prompts — list all prompts with performance data
   449→app.get('/api/ai-health/prompts', requireAdmin, async (req, res) => {
   450→  try {
   451→    const result = await pool.query(
   452→      'SELECT * FROM ai_prompts ORDER BY module, name'
   453→    );
   454→    res.json({ prompts: result.rows });
   455→  } catch (err) {
   456→    if (err.message.includes('does not exist')) {
   457→      return res.json({ prompts: [], message: 'Migration pending' });
   458→    }
   459→    res.status(500).json({ error: 'Failed to get prompts', message: err.message });
   460→  }
   461→});
   462→
   463→// GET /api/ai-health/prompts/:id — get a prompt with all versions
   464→app.get('/api/ai-health/prompts/:id', requireAdmin, async (req, res) => {
   465→  try {
   466→    const [promptResult, versionsResult, testsResult] = await Promise.all([
   467→      pool.query('SELECT * FROM ai_prompts WHERE id = $1', [req.params.id]),
   468→      pool.query('SELECT * FROM ai_prompt_versions WHERE prompt_id = $1 ORDER BY version DESC', [req.params.id]),
   469→      pool.query('SELECT * FROM ai_ab_tests WHERE prompt_id = $1 ORDER BY created_at DESC', [req.params.id]),
   470→    ]);
   471→    if (promptResult.rows.length === 0) return res.status(404).json({ error: 'Prompt not found' });
   472→    res.json({
   473→      prompt: promptResult.rows[0],
   474→      versions: versionsResult.rows,
   475→      abTests: testsResult.rows,
   476→    });
   477→  } catch (err) {
   478→    res.status(500).json({ error: 'Failed to get prompt', message: err.message });
   479→  }
   480→});
   481→
   482→// POST /api/ai-health/prompts — create or update a prompt
   483→app.post('/api/ai-health/prompts', requireAdmin, async (req, res) => {
   484→  try {
   485→    const { slug, name, module, feature, description, systemPrompt, userTemplate, temperature, maxTokens, model, changeNote } = req.body;
   486→    if (!slug || !name || !module) {
   487→      return res.status(400).json({ error: 'slug, name, and module are required' });
   488→    }
   489→
   490→    // Upsert prompt
   491→    const upsertResult = await pool.query(
   492→      `INSERT INTO ai_prompts (slug, name, module, feature, description, model)
   493→       VALUES ($1, $2, $3, $4, $5, $6)
   494→       ON CONFLICT (slug) DO UPDATE SET
