// Reset AI provider circuit breakers — protected by admin auth
app.post('/api/ai-health/reset', requireAdmin, (req, res) => {
  try {
    const { aiProvider } = require('./lib/polsia-ai');
    aiProvider.resetCircuitBreakers();
