        SELECT
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE status = 'sent' OR status = 'pending') as pending,
          COUNT(*) FILTER (WHERE status = 'accepted') as accepted,
          COUNT(*) FILTER (WHERE status = 'declined' OR status = 'rejected') as rejected,
