        SELECT
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE status = 'verified' OR status = 'processed') as verified,
          COUNT(*) FILTER (WHERE status = 'pending' OR status = 'uploaded') as pending
        FROM verification_documents
      `),
