useEffect(() => {
  // Initial load
  fetchHealth()
  fetchMetrics()
  fetchModules()
  fetchActivity()
  fetchAiUsage()
  fetchBudget()
  fetchAiLogs()
  fetchPrompts()
  fetchVerifyStatus()

  // Auto-refresh: health + metrics + modules every 30s, AI monitoring every 15s, activity every 10s
  const healthInterval = setInterval(() => {
    fetchHealth()
    fetchMetrics()
    fetchModules()
  }, 30000)
  const aiInterval = setInterval(() => {
    fetchAiUsage()
    fetchBudget()
    fetchAiLogs()
  }, 15000)
  const activityInterval = setInterval(() => fetchActivity(), 10000)

  return () => {
    clearInterval(healthInterval)
    clearInterval(aiInterval)
    clearInterval(activityInterval)
  }
}, [fetchHealth, fetchMetrics, fetchModules, fetchActivity, fetchAiUsage, fetchBudget, fetchAiLogs, fetchPrompts, fetchVerifyStatus])

// Countdown timer
useEffect(() => {
  const timer = setInterval(() => {
    setCountdown(prev => (prev > 0 ? prev - 1 : 30))
  }, 1000)
  return () => clearInterval(timer)
}, [lastRefresh])
